"""Runner protocol and implementations for Python and TypeScript components.

PythonRunner: wraps the existing Python executor for Python-authored components.
NodeRunner: manages a long-lived Node subprocess for TypeScript-authored components.
discover_ts_components: shells out to npx zhanla-sdk-ts discover to get manifests.
"""
from __future__ import annotations

import asyncio
import json
import os
import secrets
import subprocess
import sys
from pathlib import Path
from typing import Any

from zhanla_cli.manifest import ComponentManifest


# ---------------------------------------------------------------------------
# .env.local loader
# ---------------------------------------------------------------------------

def load_dotenv_local(start_dir: str | Path | None = None) -> Path | None:
    """Parse .env files and inject vars into os.environ (skip already-set keys).

    Walks up from start_dir (defaults to cwd) until it finds a directory
    containing .env.local or .env, then loads both if present. .env.local
    takes priority over .env. Returns the path of the last file loaded, or None.
    """
    _ENV_FILES = [".env.local", ".env"]

    directory = Path(start_dir or Path.cwd()).resolve()
    env_dir: Path | None = None
    for parent in [directory, *directory.parents]:
        if any((parent / name).is_file() for name in _ENV_FILES):
            env_dir = parent
            break

    if env_dir is None:
        return None

    def _apply(path: Path) -> None:
        with path.open() as f:
            for line in f:
                line = line.strip()
                if not line or line.startswith("#") or "=" not in line:
                    continue
                key, _, value = line.partition("=")
                key = key.strip()
                value = value.strip().strip('"').strip("'")
                if key and key not in os.environ:
                    os.environ[key] = value

    last_loaded: Path | None = None
    for name in _ENV_FILES:
        candidate = env_dir / name
        if candidate.is_file():
            _apply(candidate)
            last_loaded = candidate

    return last_loaded


# ---------------------------------------------------------------------------
# Provider API key configs
# ---------------------------------------------------------------------------

# Ordered so explicit provider-routed prefixes (openrouter/, bedrock/, etc.)
# are matched before generic model-name prefixes (claude, gpt-, gemini).
_PROVIDER_CONFIGS: list[dict] = [
    {
        "name": "OpenRouter",
        "prefixes": ("openrouter/",),
        "env_vars": ["OPENROUTER_API_KEY"],
        "validate_url": "https://openrouter.ai/api/v1/models",
        "auth_header": lambda k: {"Authorization": f"Bearer {k}"},
    },
    {
        "name": "AWS Bedrock",
        "prefixes": ("bedrock/",),
        "env_vars": ["AWS_ACCESS_KEY_ID", "AWS_SECRET_ACCESS_KEY"],
        "validate_url": None,
        "auth_header": None,
    },
    {
        "name": "Vertex AI",
        "prefixes": ("vertex_ai/", "vertex/"),
        "env_vars": ["GOOGLE_APPLICATION_CREDENTIALS"],
        "validate_url": None,
        "auth_header": None,
    },
    {
        "name": "Azure OpenAI",
        "prefixes": ("azure/", "azure_openai/"),
        "env_vars": ["AZURE_OPENAI_API_KEY", "AZURE_OPENAI_ENDPOINT"],
        "validate_url": None,
        "auth_header": None,
    },
    {
        "name": "Anthropic",
        "prefixes": ("claude",),
        "env_vars": ["ANTHROPIC_API_KEY"],
        "validate_url": "https://api.anthropic.com/v1/models",
        "auth_header": lambda k: {"x-api-key": k, "anthropic-version": "2023-06-01"},
    },
    {
        "name": "OpenAI",
        "prefixes": ("gpt-", "o1-", "o2-", "o3-", "o4-", "text-embedding-"),
        "env_vars": ["OPENAI_API_KEY"],
        "validate_url": "https://api.openai.com/v1/models",
        "auth_header": lambda k: {"Authorization": f"Bearer {k}"},
    },
    {
        "name": "Google Gemini",
        "prefixes": ("gemini",),
        "env_vars": ["GOOGLE_API_KEY"],
        "validate_url": "https://generativelanguage.googleapis.com/v1beta/models",
        "auth_header": None,
        "auth_params": lambda k: {"key": k},
    },
]


def _model_provider(model: str) -> dict | None:
    """Return the matching provider config for the given model string, or None."""
    lower = model.lower()
    for cfg in _PROVIDER_CONFIGS:
        if any(lower.startswith(p) for p in cfg["prefixes"]):
            return cfg
    return None


def check_required_api_keys(models: set[str]) -> list[str]:
    """Pre-flight check for API keys required by the given model names.

    Returns a list of human-readable error strings (empty = all good).
    Missing env vars are always reported. Invalid keys are detected via a
    lightweight HTTP GET; network/TLS errors are silently ignored (fail-open).
    Add new providers by appending a dict to _PROVIDER_CONFIGS above.
    """
    import httpx

    seen_providers: set[str] = set()
    errors: list[str] = []

    for model in models:
        cfg = _model_provider(model)
        if cfg is None:
            continue
        name: str = cfg["name"]
        if name in seen_providers:
            continue
        seen_providers.add(name)

        env_vars: list[str] = cfg["env_vars"]
        primary_key: str | None = None
        missing: list[str] = []

        for var in env_vars:
            val = os.environ.get(var, "").strip()
            if not val:
                missing.append(var)
            elif primary_key is None:
                primary_key = val

        if missing:
            for var in missing:
                errors.append(
                    f"{name} API key not found: {var} is not set. "
                    f"Add it to your .env.local file or export it as an environment variable."
                )
            continue

        validate_url: str | None = cfg.get("validate_url")
        auth_header_fn = cfg.get("auth_header")
        auth_params_fn = cfg.get("auth_params")
        if validate_url is None or primary_key is None:
            continue
        if auth_header_fn is None and auth_params_fn is None:
            continue

        try:
            headers = auth_header_fn(primary_key) if auth_header_fn else {}
            params = auth_params_fn(primary_key) if auth_params_fn else {}
            resp = httpx.get(validate_url, headers=headers, params=params, timeout=8.0)
            if resp.status_code == 402:
                errors.append(
                    f"{name} account is unavailable: {env_vars[0]} is set, but the provider "
                    "returned 402 Payment Required. Check your credits or billing status."
                )
            elif resp.status_code in (400, 401, 403):
                errors.append(
                    f"Invalid {name} API key: {env_vars[0]} is set but was rejected "
                    f"({resp.status_code}). Check the value in your .env.local file."
                )
        except Exception:
            pass

    return errors


class RunnerError(RuntimeError):
    """Raised when a runner encounters a fatal setup or execution error."""


def _ensure_ts_sdk_available() -> None:
    """Verify that the TS SDK CLI is already installed without triggering installs."""
    try:
        result = subprocess.run(
            ["npx", "--no-install", "zhanla-sdk-ts"],
            capture_output=True,
            text=True,
            timeout=15,
        )
    except FileNotFoundError:
        raise RunnerError(
            "TypeScript support requires Node.js and npx. "
            "Install Node.js and add @zhanla/sdk-ts in the current project."
        )

    stderr = (result.stderr or "").strip()
    stdout = (result.stdout or "").strip()
    details = stderr or stdout

    # The TS helper exits non-zero when invoked without a subcommand, but that
    # still proves the executable is installed and reachable via npx.
    if "Usage: zhanla-sdk-ts" in details:
        return

    raise RunnerError(
        "TypeScript support requires @zhanla/sdk-ts to already be installed "
        "in the current project. Install it with `npm install @zhanla/sdk-ts`."
        + (f" Error: {details}" if details else "")
    )


# ---------------------------------------------------------------------------
# Language detection
# ---------------------------------------------------------------------------

def detect_language(filepath: str) -> str:
    """Infer component language from file extension. Returns 'python' or 'typescript'."""
    suffix = Path(filepath).suffix.lower()
    if suffix == ".py":
        return "python"
    if suffix == ".ts":
        return "typescript"
    raise ValueError(
        f"Unsupported file extension: {suffix!r} in {filepath!r}. "
        f"Use .py for Python components or .ts for TypeScript components."
    )


def validate_same_language(component_lang: str, eval_lang: str | None) -> None:
    """Raise ValueError if component and eval languages don't match."""
    if eval_lang is None:
        return
    if component_lang != eval_lang:
        raise ValueError(
            f"Component and eval must be implemented in the same language. "
            f"Component is {component_lang!r} but eval is {eval_lang!r}. "
            f"Mixed-language local runs are not supported in v1."
        )


# ---------------------------------------------------------------------------
# TypeScript discovery
# ---------------------------------------------------------------------------

def _python_discover_env() -> dict[str, str]:
    env = dict(os.environ)
    repo_root = Path(__file__).resolve().parents[3]
    sdk_py_root = repo_root / "packages" / "sdk-py"
    if sdk_py_root.is_dir():
        existing = env.get("PYTHONPATH", "")
        path_entries = [str(sdk_py_root)]
        if existing:
            path_entries.append(existing)
        env["PYTHONPATH"] = os.pathsep.join(path_entries)
    return env


def discover_python_components(spec: str) -> list[ComponentManifest]:
    """Shell out to `python -m zhanla.discover file.py:component-key` and parse the result.

    Returns a leaf-first list of ComponentManifest objects covering the full transitive
    closure of the targeted component. The root component (the target) is the last
    element. Every dependency appears before any component that depends on it.
    Raises ValueError if discovery fails or output is malformed.
    """
    result = subprocess.run(
        [sys.executable, "-m", "zhanla.discover", spec],
        capture_output=True,
        text=True,
        timeout=30,
        env=_python_discover_env(),
    )

    if result.returncode != 0:
        stderr = (result.stderr or "").strip()
        raise ValueError(
            f"Discovery failed for {spec}: {stderr}" if stderr else f"Discovery failed for {spec}"
        )

    stdout = (result.stdout or "").strip()
    try:
        raw_manifests = json.loads(stdout)
    except json.JSONDecodeError as exc:
        raise ValueError(
            f"Invalid manifest JSON from zhanla.discover: {exc}. Output was: {stdout[:200]!r}"
        )

    if not isinstance(raw_manifests, list):
        raise ValueError(
            f"Expected a JSON array from zhanla.discover, got: {type(raw_manifests).__name__}"
        )

    manifests = []
    for raw in raw_manifests:
        if not isinstance(raw, dict):
            continue
        manifests.append(ComponentManifest(**{
            k: v for k, v in raw.items()
            if k in ComponentManifest.__dataclass_fields__
        }))
    return manifests


def discover_ts_components(spec: str) -> list[ComponentManifest]:
    """Shell out to `npx zhanla-sdk-ts discover <file.ts[:ExportName]>` and parse the result.

    The spec may be a plain file path or `file.ts:ExportName` for targeted closure discovery.
    Returns a leaf-first list of ComponentManifest objects covering the full transitive
    closure of the targeted component. The root component (the target) is the last
    element. Every dependency appears before any component that depends on it.
    Raises RunnerError if zhanla-sdk-ts is not installed.
    Raises ValueError if no components are found or output is malformed.
    """
    _ensure_ts_sdk_available()
    result = subprocess.run(
        ["npx", "--no-install", "zhanla-sdk-ts", "discover", spec],
        capture_output=True,
        text=True,
        timeout=30,
        env={**os.environ, "ZHANLA_INTERNAL": secrets.token_hex(32)},
    )

    if result.returncode != 0:
        stderr = (result.stderr or "").strip()
        raise ValueError(
            f"No TypeScript components found in {spec}."
            + (f"\n\n{stderr}" if stderr else "")
        )

    stdout = (result.stdout or "").strip()
    try:
        raw_manifests = json.loads(stdout)
    except json.JSONDecodeError as exc:
        stderr = (result.stderr or "").strip()
        detail = f"\n\nstderr:\n{stderr}" if stderr else f"\n\nstdout:\n{stdout}"
        raise ValueError(
            f"Invalid manifest JSON from zhanla-sdk-ts discover: {exc}.{detail}"
        )

    if not isinstance(raw_manifests, list):
        raise ValueError(
            f"Expected a JSON array from zhanla-sdk-ts discover, got: {type(raw_manifests).__name__}"
        )

    manifests = []
    for raw in raw_manifests:
        if not isinstance(raw, dict):
            continue
        manifests.append(ComponentManifest(**{
            k: v for k, v in raw.items()
            if k in ComponentManifest.__dataclass_fields__
        }))

    return manifests


# ---------------------------------------------------------------------------
# PythonRunner
# ---------------------------------------------------------------------------

class PythonRunner:
    """Runner for Python-authored components. Wraps the existing executor."""

    def __init__(
        self,
        component: Any,
        eval_component: Any | None,
    ) -> None:
        self._component = component
        self._eval_component = eval_component

    def start(self) -> None:
        """No-op: Python runner uses in-process execution."""

    def stop(self) -> None:
        """No-op: no subprocess to clean up."""

    async def run_row(
        self,
        row: dict,
        trigger_run_id: str,
    ) -> dict:
        """Execute one row through the Python component (and optional eval).

        Returns a dict with:
        - status: "ok" | "error"
        - output: the component output dict
        - eval_output: the eval output dict (if eval component provided)
        - error: error message string (on failure)
        """
        from zhanla_cli.executor import execute_row

        result = await execute_row(
            self._component,
            self._eval_component,
            row,
            trigger_run_id,
        )

        if result.component_trace.status == "failed":
            return {
                "status": "error",
                "error": result.component_trace.error or "Unknown error",
            }

        response: dict = {
            "status": "ok",
            "output": result.component_trace.output or {},
        }

        if result.eval_trace is not None:
            if result.eval_trace.status == "failed":
                response["eval_error"] = result.eval_trace.error or "Eval error"
            else:
                response["eval_output"] = result.eval_trace.output or {}

        return response


# ---------------------------------------------------------------------------
# NodeRunner
# ---------------------------------------------------------------------------

class NodeRunner:
    """Runner for TypeScript-authored components.

    Manages a single long-lived Node subprocess per zhanla run invocation.
    Communicates with the subprocess over NDJSON on stdin/stdout.
    """

    def __init__(
        self,
        manifest: ComponentManifest,
        eval_manifest: ComponentManifest | None,
        file_path: str,
    ) -> None:
        self._manifest = manifest
        self._eval_manifest = eval_manifest
        self._file_path = file_path
        self._process: subprocess.Popen | None = None

    def start(self) -> None:
        """Start the long-lived Node subprocess."""
        target_name = self._manifest.name
        target = f"{self._file_path}:{target_name}"
        _ensure_ts_sdk_available()
        command = ["npx", "--no-install", "zhanla-sdk-ts", "run", target]
        if self._eval_manifest is not None:
            eval_target = (
                f"{self._eval_manifest.file_path}:{self._eval_manifest.name}"
                if self._eval_manifest.file_path and self._eval_manifest.name
                else None
            )
            if eval_target:
                command.extend(["--eval", eval_target])
        try:
            self._process = subprocess.Popen(
                command,
                stdin=subprocess.PIPE,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                env={**os.environ, "ZHANLA_INTERNAL": secrets.token_hex(32)},
            )
        except FileNotFoundError:
            raise RunnerError(
                "TypeScript support requires Node.js and npx. "
                "Install Node.js and add @zhanla/sdk-ts in the current project."
            )

    def stop(self) -> None:
        """Terminate the subprocess if running."""
        if self._process is not None:
            try:
                self._process.stdin.close()  # type: ignore[union-attr]
                self._process.wait(timeout=5)
            except Exception:
                self._process.kill()
            finally:
                self._process = None

    async def run_row(
        self,
        row: dict,
        trigger_run_id: str,
    ) -> dict:
        """Send one row to the subprocess and read back the NDJSON result."""
        if self._process is None:
            return {"status": "error", "error": "NodeRunner not started"}

        def _read_stderr() -> str:
            if self._process is None:
                return ""
            try:
                # Non-blocking stderr drain — read what's available without blocking.
                import select as _select
                ready, _, _ = _select.select([self._process.stderr], [], [], 0.1)
                if ready:
                    return (self._process.stderr.read(4096) or b"").decode(errors="replace").strip()  # type: ignore[union-attr]
            except Exception:
                pass
            return ""

        # Check if subprocess has crashed
        if self._process.poll() is not None:
            exit_code = self._process.poll()
            stderr = _read_stderr()
            detail = f"\n\n{stderr}" if stderr else ""
            return {
                "status": "error",
                "error": f"TypeScript subprocess exited unexpectedly (exit code {exit_code}).{detail}",
            }

        # Write the row as a JSON line to stdin
        line = json.dumps(row).encode() + b"\n"
        try:
            self._process.stdin.write(line)  # type: ignore[union-attr]
            self._process.stdin.flush()  # type: ignore[union-attr]
        except BrokenPipeError:
            stderr = _read_stderr()
            detail = f"\n\n{stderr}" if stderr else ""
            return {"status": "error", "error": f"TypeScript subprocess pipe broken.{detail}"}

        # Read the result line from stdout
        result_line = self._process.stdout.readline()  # type: ignore[union-attr]
        if not result_line:
            exit_code = self._process.poll()
            stderr = _read_stderr()
            detail = f"\n\n{stderr}" if stderr else ""
            return {
                "status": "error",
                "error": f"TypeScript subprocess produced no output (exit code {exit_code}).{detail}",
            }

        try:
            return json.loads(result_line.decode())
        except json.JSONDecodeError as exc:
            stderr = _read_stderr()
            detail = f"\n\n{stderr}" if stderr else ""
            return {
                "status": "error",
                "error": f"Invalid JSON from TypeScript subprocess: {exc}.{detail}",
            }
